#include <vector>
#include <queue>
#include <unordered_map>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build the graph
    unordered_map<long long, vector<pair<long long, long long>>> graph;
    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long s = edge[2];
        long long e = edge[3];
        graph[u].emplace_back(v, s, e);
    }

    // Priority queue: (time, node)
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    pq.push({0, 0});

    // Visited dictionary to keep track of the earliest time we reach each node
    unordered_map<long long, long long> visited;

    while (!pq.empty()) {
        long long time = pq.top().first;
        long long node = pq.top().second;
        pq.pop();

        // If we have already reached this node with an earlier time, skip
        if (visited.find(node) != visited.end() && visited[node] <= time) {
            continue;
        }

        // Mark the earliest time we reach this node
        visited[node] = time;

        // If we reached the destination, return the time
        if (node == n - 1) {
            return time;
        }

        // Explore all outgoing edges from the current node
        for (const auto& [neighbor, start, end] : graph[node]) {
            // Check if we can use this edge at the current time
            if (start <= time && time <= end) {
                // We can take this edge and arrive at the neighbor at time + 1
                long long new_time = time + 1;
                if (visited.find(neighbor) == visited.end() || new_time < visited[neighbor]) {
                    pq.push({new_time, neighbor});
                }
            } else {
                // If the edge is not available at the current time, we can wait
                // Wait until the start time of the edge
                long long wait_time = max(0LL, start - time);
                long long new_time = time + wait_time;
                if (visited.find(neighbor) == visited.end() || new_time < visited[neighbor]) {
                    pq.push({new_time, neighbor});
                }
            }
        }
    }

    // If we exhaust the queue without reaching the destination
    return -1;
}
